from collections import Counter

class Solution(object):
    def smallestPalindrome(self, s, k):
        freq = Counter(s)
        n = len(s)
        mid_char = ''
        half_freq = {}
        for c, cnt in sorted(freq.items()):
            half_freq[c] = cnt // 2
            if cnt % 2 == 1:
                mid_char = c
        half_len = n // 2
        def count_perms(freq_dict, cap):
            # Multinomial: total! / prod(fi!) capped at cap+1
            total = sum(freq_dict.values())
            if total == 0:
                return 1
            result = 1
            fi = [f for f in freq_dict.values() if f > 0]
            # Compute iteratively
            for i in range(1, total + 1):
                result *= i
                if result > cap:
                    return cap + 1
            for f in fi:
                for i in range(1, f + 1):
                    result //= i
            return result
        # Check if total permutations >= k
        total = count_perms(half_freq, k)
        if total < k:
            return ""
        # Greedily build first half
        first_half = []
        remaining = dict(half_freq)
        for pos in range(half_len):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                if remaining.get(c, 0) > 0:
                    remaining[c] -= 1
                    cnt = count_perms({ch: f for ch, f in remaining.items() if f > 0}, k)
                    if cnt >= k:
                        first_half.append(c)
                        break
                    else:
                        k -= cnt
                        remaining[c] += 1
        second_half = first_half[::-1]
        return ''.join(first_half) + mid_char + ''.join(second_half)
